SELECT AVG(p.age) AS mean_age
FROM patients p
WHERE p.patient_id IN (
    SELECT d.patient_id 
    FROM diagnostic_tests d
) AND p.patient_id IN (
    SELECT v.patient_id 
    FROM patient_visits v
) AND p.age > 50;

SELECT doctor_id, COUNT(*) 
FROM diagnostic_tests 
GROUP BY doctor_id;

SELECT COUNT(*) 
FROM patient_visits 
WHERE strftime('%m', visit_date) = '02';

SELECT COUNT(*) 
FROM patients 
WHERE patient_id IN (
    SELECT patient_id 
    FROM diagnostic_tests
) AND output = 1;

SELECT patient_id, age, sex, cp, trtbps, chol, fbs, restecg, thalach, exng, oldpeak, slp, caa, thall, output, patient_name, address, phone_number, email, emergency_contact_name, emergency_contact_phone, date_of_birth, height, weight, blood_type, smoker, alcohol_consumer, family_history, insurance_provider, insurance_policy_number
FROM patients
ORDER BY age DESC;
